INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (1, 3, 18, 4, 'This desk is very study and it i has  a beautiful finish,  I think that it a just a little  pricey for the size.', '2026-04-19 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (2, 34, 27, 5, 'Great item', '2025-05-10 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (3, 25, 186, 5, 'Perfect fit for my bedroom, been wanting one since I was a little girl', '2025-12-01 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (4, 4, 7, 3, 'We use this on a trundle bed.  So, it does not get that much use.  This was a much better choice than getting a low end spring mattress for the same price.  I do not think I would use this on anything other than a trundle.', '2025-06-12 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (5, 39, 56, 3, 'The product is fine...just seemed like it took awhile in the mail for something small you could throw in an envelope and mail.  Not unhappy just moderately satisfied.', '2025-06-23 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (6, 40, 31, 5, 'Love this product, amazing delivery, thank you', '2026-03-12 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (7, 22, 97, 5, 'I love this bench, had one in Black for over five years, and moved it more than 5 times to different houses after a few chips and broken pieces, I decided to buy the White one as it matches our current home decor better, plus it is much easier to locate shoes especially black ones! the black cubbie bench was too dark, and most of our shoes blended in and hard to see. This is perfect. Easy to put together. I painted the back white as well, as it was going in an area with the all sides shown.', '2025-05-24 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (8, 38, 145, 5, 'Have had this for over a year.  Very well made and durable!  Great storage capacity.', '2026-01-21 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (9, 40, 48, 5, 'This is the best step stool I have ever used.  So compact when collapsed so is very easy to store.. no hidden latches.  Have already recommended to friends.', '2025-12-17 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (10, 39, 20, 5, 'my son loves it!', '2025-06-02 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (11, 26, 197, 5, 'Great product', '2025-09-19 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (12, 39, 198, 5, 'bought with sleep contour 8&#34; foam. arrived ontime and my kid had no trouble assembling it. shipped it to his off campus apt.. he says its most comfortable bed hes ever owned!', '2025-11-11 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (13, 10, 71, 5, 'Delivery was on time. I was very satisfied with the product. The table is very sturdy and it exceeds my expectations!', '2026-03-25 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (14, 28, 16, 5, 'Exactly as pictured. Plush, soft and great for in front of a sofa.', '2025-12-14 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (15, 26, 46, 5, 'Beautiful table.  It''s good quality and heavy.  Put it together by myself, it took about 3 hours, but the instructions were the best and clearest of any item I''ve had to build.  I was worried because it looked like there was a crack in the top of the table itself until I looked closer - that''s how good the laminate is, it REALLY looks real.  Love it and would purchase again.', '2025-09-12 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (16, 37, 101, 1, 'I have cleaned up the last mess from using this tray, the legs collapsed again. It was also much larger and bulkier than I wanted.<br />But if your looking for a big tray without a lot of support this is the one.', '2026-01-24 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (17, 21, 37, 3, 'First one came in damaged. Ok bed for the price.', '2025-07-23 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (18, 24, 158, 4, 'Good deal to get a nice chair for study in a low price', '2025-05-31 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (19, 40, 67, 5, 'Comfortable and easy to fix...', '2026-03-04 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (20, 36, 187, 5, 'As advertised. Very comfortable. Great color. Prompt delivery.', '2025-12-18 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (21, 3, 128, 5, 'Very nice rug for a reasonable price. Exceeded my expectations.', '2026-02-08 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (22, 3, 10, 5, 'Product was as described. Delivered on time. Overall a sturdy box spring. Not at all difficult to put together. We bought Mom a tall foam mattress from Costco. With this low profile box spring my Mother has no problems get in and out of bed now. Also good quality materials for the price, which wasn''t bad either. I recommend and will purchase again if needed.', '2025-05-20 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (23, 22, 180, 3, 'Functional but too lightweight - I ordered 2 and attached them together', '2025-11-08 13:09:02');
