INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (51, 28, 55, 4, 'This is very concentrated and smells okay, but the scent does not last after drying. My laundry just smelled like clean clothes, which is fine, but kind of defeats the purpose of jasmine-scented laundry detergent. It cleans fine, doesn''t cause any allergic reactions, and the packaging is fine. However, it had leaked a bit during shipping despite being in a plastic bag.', '2026-04-02 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (52, 28, 17, 5, 'Just bought this mattress, and it is wonderful! With any new mattress I have bought, it takes a few days to get used to it. Not with this mattress! Did not have to get used to it at all. Slept the whole nite thru. This is not the less expensive and not the most expensive...right in between. You won''t go wrong with this mattress.', '2026-02-23 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (53, 31, 44, 4, 'This is a beautiful island but it is not solid wood. The back consists of 2 pieces of board that I think are plastic they are only about 1/4 inch thick. I think the shelves are particle board.  It arrives in 3 boxes. One box consists of the top with the drawers already attached. You will need to attach the leaf.  It has very clear instructions. We did have a problem with both of the doors not wanting to close so we took the hinges off and turned them over and reattached them. One door the hinge ', '2025-05-04 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (54, 23, 113, 5, 'This rug is kind of  unique and that is what I was looking for ; combines couple of different rug materials, shag and berber, to present such a contemporary, interesting look. Very soft ! Seems well made. Colors are true to the picture, and go very nicely with our chocolate brown sectional in a neutral color room.  Highly recommend.', '2025-12-22 13:09:02');
