INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (72, 31, 65, 1, 'This was one of the worst purchases I''ve ever made.  The drawers and top are chipped, the directions are poorly represented pictures... there are no premarked holes for the areas the need nails and the screw holes for the drawers don''t line up, leading to hours of frustration and misaligned construction. I''d have done better with ikea furniture and may wind up doing just that. This will be an expensive item at my curb.', '2025-11-05 13:09:02');
