INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (78, 25, 200, 2, 'This chair is a typical manager''s chair. There was nothing showing the weight limits, but width wise, it definitely isn''t for a big person. I definitely overpaid for what is actually just a basic office chair. It was also slightly difficult to put together. The screw holes weren''t drilled correctly and I had a hard time getting the screws to catch. The two stars are for the looks. I would give another 1/2 star for comfort if I could.  If you''re big, I wouldn''t recommend. If you''re not big,', '2026-02-28 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (79, 21, 61, 5, 'We love the headboard. The fabric and tufted button work looks great! It is high quality and looks very modern and elegant. We have an ikea storage bed in one of the rooms and we simply put the headboard against the wall in between the wall and the bed and there was no need to screw the headboard. It appears nice and stable. Looks great!', '2025-09-26 13:09:02');
