INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (81, 33, 14, 2, 'Convenient remote control holder that can be attached to the side of a dresser or bed stand.  Comes with both wood screws and Velcro for attachment.  However, the screws broke off at the head when screwing into wood, before the screwhead was even close to the wood!  This damaged the dresser by leaving unusable holes, as the base of the screws could not be removed from the wood!  I''ve never had screw heads snap off before, and on closer inspection, the included screws appeared to be hollow!!!', '2025-09-14 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (82, 32, 46, 4, 'This would have been great if the kit had all of the correct pieces. I could not finish assembly because it had two left side panels instead of one left and one right. Now I have to wait to finish assembling it and hope the replacement parts are the right color. On the positive side, it did arrive about 4 days earlier than anticipated.', '2025-10-09 13:09:02');
