INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (86, 32, 108, 5, 'I love Sauder pieces. This desk was my 30th piece, and I just ordered my 31st. I call Sauder the Cadillac of Walmart. Their attention to detail is astonishing. It is par for the course to have a few pieces arrive damaged in shipping, and yes Sauder, obviously damaged in the factory BEFORE packaging. But Sauder makes it right (usually, see below). Just hop on their website and order the replacement pieces you need, free of charge. Set aside the project for a week. My parts'' orders arrive within ', '2026-01-28 13:09:02');
