INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (124, 23, 74, 5, 'I bought this in full-size for my teenage grandson and he just loves it. He said it''s the most comfortable bed he''s ever slept on - now his little brother wants one...so do I!  It''s a great price for this product when you compare it to other brands too. It is delivered all rolled up, but easily unpacks and is ready to use in no time.  BTW, keep in mind that these mattresses are designed for platform beds. The manufacturer does not make boxsprings for this mattress. Thanks, Amazon, for a good ', '2026-03-17 13:09:02');
