INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (130, 34, 166, 5, 'So after reading so many great reviews about this mattress, I decided to go ahead and order it. I was going to order directly from the company but remembered Discover had a promo for 5% back on Amazon purchases. Shipping was fast! The mattress came to my doorstep within a few days. Setup was easy... you basically just cut open the two layers of plastic that it is wrapped in and let the mattress expand. The mattress is on the firm side, which I kind of prefer, but it took about a week to get used', '2025-11-05 13:09:02');
