INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (158, 37, 155, 5, 'A full size mattress is approximately 72-inches long by 54-inches wide, and this set was advertised as being 8-inches thick.  When this set arrived, in two boxes, I went back to the listing thinking that I had misunderstood the listing.<br /><br />The box for the spring was only 54-inches by 47-inches by 5-inches.  I felt that there was no way an 8-inch spring could fit in it.  I was certainly surprised when we unfolded the spring and it expanded itself to a full size and 8-inch thickness.  I di', '2025-08-07 13:09:02');
