INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (211, 10, 26, 5, 'The arctic dream mattress is 10” of total comfort and restful night. Of the 10”, 3” of it is cooling gel on top and 6.25” of polyurethane foam and top with .75” of really nice soft quilt. I honestly feel like I’m sleeping on a really expensive mattress that should have cost me in the thousands but this bed is affordable. Sometimes you have the mentality of “You get what you pay for” but this is an exception. The bed is a nice quality bed, comfortable, thick, and firmer than most pillow top mattr', '2025-07-03 13:09:02');
