INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (215, 40, 151, 3, 'While the bar stools themselves are quite nice, the packing left a lot to be desired.  Both bottoms of the set were damaged, one subtly, and one quite obviously.  The third party seller was quick to send replacements which was much appreciated, unfortunately before noticing the subtly dented bottom we had already put the stools together, and can''t manage to unseat the bottom in order to replace it with the new one.  No big deal I thought, the damage is slight so I''ll just put together the othe', '2026-01-21 13:09:02');
