INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (220, 35, 185, 4, 'This is a nice looking chair.  It sits well, and is a good height.  The seat is quite large.  The stripes do line up well on back of chair with seat of chair.  The boxing stripe on the seat cushion is a little skewed.  Wish that were not so.  The chair is fairly easy to put together.  Do not be in a hurry to put it together.  Do not tighten the screws as you go or you will have issues with parts aligning.', '2026-04-05 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (221, 21, 99, 4, 'I live in a small apartment, and like many small apartments, this one doesn''t have a separate dining area.  I have a tiny corner of the living room with which to place a dining table – so I really needed one that was nice and compact.  However, I also wanted one that was big enough to serve as extra table space for when I''m working on prepping a larger meal (because, yes, the kitchen is tiny, too).  This was a bit of dilemma before I struck on the idea of getting a table with drop leaves.  Unf', '2025-12-01 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (222, 27, 176, 5, 'I decided to get the arctic dreams 10 inch cooling gel foam mattress by DreamFoam Bedding. Here''s what I think about it.<br /><br />* Queen mattress<br />* 10 inch<br />* made in the USA<br />* cooling gel foam<br />* 3 inches of gel foam<br /><br />When this box was delivered I was highly skeptical. It honestly didn''t look at the size of a large twin. We unleashed it from its packaging. With in two minutes it had expanded to be a 10 inch mattress. It was truly amazing. I''m still scratching m', '2025-09-10 13:09:02');
