INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (224, 33, 174, 1, 'Not a good investment. The old saying you get what you pay for is true in this case. Two of the slate inserts were loose and the others two were not centered and had the cement on the top and around some of the sides. No effort to size the slate to fit the opening. The finish appears to only have a single coat and has a lot of nicks and pits. The table is also not level when assembled. The top will not hold much weight because of the way it is constructed. If you push hard on the top it will fal', '2025-10-19 13:09:02');
