INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (238, 30, 155, 5, 'I have to admit that I was skeptical about this bed but wow was I surprised.  It is well made, huge and definitely makes a statement.  It arrived in two very large boxes but it was well packed and the contents had no damage.  It took 10 minutes to unpack and inventory the parts, very few parts considering the size of the bed.  The assembly took under an hour from beginning to end.  I would definitely recommend an electric screw driver, the supplied allen wrench will do the job but it will take a', '2025-05-13 13:09:02');
