INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (639, 10, 31, 1, 'Worked great until it stopped working.    Twice I''ve had one of these go out on me.  The first time I ran it without the water turned on (my fault, but it can detect that there''s no water nd it keeps running anyway -- what the hell!) and it developed a leak.  I''d had it about 30 days and the company exchanged it for me.  The 2nd time I have been using it correctly with great results for about 1 year.  Then yesterday it started making a different noise than it usually makes -- it sounded like ', '2026-02-11 13:09:02');
