INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (646, 24, 187, 3, 'I rarely do reviews, but wanted to let people know about the deceptive marketing on this dishwasher.  We did a remodel and due to space constraints needed an 18 inch dishwasher.  We replaced a Kenmore dishwasher rated at 50 db.  The Bosch sounds like a freight train in our kitchen compared to the Kenmore.  We couldn''t tell the Kenmore was on, but with the Bosch we can''t run it when we are home.  It drowns out the TV and forget about getting any sleep when it is running (the bedroom is on one s', '2026-03-15 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (647, 39, 158, 4, 'Note that this only chills to a low of 51 degrees. I probably would have bought another model had I realized this as I like my white wine in the mid-40s. However it does function well, is a very nice looking refrigerator, and I don''t find it to be too loud like some other reviewers (maybe that depends on the surface on where it sits.) Also note that it only fits slim bottles of wine - anything that is a bit larger in circumference on the bottom only fits in a few of the spaces.', '2026-03-23 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (648, 38, 193, 3, 'Nice unit, however, only works with what I would say is standard slim wine bottles. Any bottle that is odd size will not fit on the racks.  So, to use the fridge for varying size wine bottles you would have to remove some shelves to allow them to fit which reduces the capacity.  I''m sending mine back, which has not been a problem so far working with Amazon.', '2025-08-08 13:09:02');
