INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (700, 32, 71, 4, 'Where do I begin? I received my brand new lil washer machine today. Couldn’t be more excited to do laundry! After 12 years of schlepping to the laundry mat, dodging cars to cross the street, counting pennies to convert to quarters,  I finally invested in my own private washing machine. I have to admit, this is my 3rd attempt at buying a portable washing machine in the last month. One of the main reasons why I made a decision to make this type of purchase is that the laundry-mat disgusts me. Afte', '2026-01-12 13:09:02');
