INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (728, 38, 134, 5, 'We loved it!! Installed very easily, no leaks only remember to purge before hand to remove impurities and air in the filter.  Not having to pay the hefty GE price!! Even if GE is compatible with NFS/ANSI 56 and the Waterfall Filter meets NFS/ANSI 42 and not 56, your county water companies many times have to meet even more stringent health standards than 56.  No worry, we will purchase this filter again. Cheers &amp; good drinking!', '2025-06-01 13:09:02');
