INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (778, 32, 79, 5, 'We have a hard time keeping ice trays full at our lake house in the summer.  This is great. It''s not silent when it''s making a batch of ice but I couldn''t call it loud either. The ice falling into the bin can be loud when you don''t know it''s going to happen.<br /><br />It''s not high volume but we rarely ran out with a family of four in the summer putting ice in our drinks.', '2025-09-05 13:09:02');
