INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (781, 3, 4, 1, 'I have a frigidaire fgus2632lp which I believe this model replaced.  Mine is also a piece of junk.  Icemaker had 3 service calls in first 3 months.  I assumed the water dispenser put out chilled water but it doesn''t, which sales people didn''t even mention. Fridge interior cannot maintain constant temp; items toward rear(like pickles in a jar) have gotten frozen.  Items come out of fridge damp, and shelves are damp.  I will never buy any frigidaire product again.  I have bought another 2 years ', '2025-08-12 13:09:02');
