INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (827, 4, 189, 2, 'My range hood vent is 6&#34;, and the bathroom vent is 3&#34;, so this didn''t fit either. I adapted it to fit over the bathroom vent anyway. In a strong wind, the light-weight flaps fly open and shut easily, defeating the purpose of the draft protection. It needs an additional shroud to block the wind.<br /><br />If you are looking for an excellent dryer vent, use the Lambro Ind. 289 Dryer Vent Closure instead. It is solid, sturdy, and works well. It just doesn''t work horizontally as for range', '2025-11-10 13:09:02');
