INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (835, 33, 170, 5, 'There was quite a bit of hand wringing two weeks ago when the glass turntable plate went flying out of our microwave oven and shattered in a million pieces all over the kitchen floor. I won''t name the culprit, but he''s the one who required tweezer &#34;surgery&#34; to get the glass shard out of the sole of his foot.<br /><br />Where ever would one find a replacement part for a Sharp microwave oven purchased in 2001? To my great relief, from Martin Microwave, here on Amazon!<br /><br />You need', '2025-07-23 13:09:02');
