INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (848, 3, 80, 2, 'Definitely heed the poor reviews on this product.  I wish I had.<br /><br />Cooling system gave out once the unit was 3 months our of warranty; however, KingsBottle would not honor the problem.  Customer service was absolutely horrible.  I''ve never experienced anything like it.  Once they indicated they would not warranty the unit I asked if they had a service agent that could fix it.  At first they said they did as I was so close to their headquarters; however, I never received any information', '2026-03-25 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (849, 24, 100, 5, 'I have had my wine cooler for a little over one week.  I love it.  There is absolutely no noise from it.  The very first day, it did run a lot and made a bit of noise as it was working its way down to the chosen temperature.  I am wondering if those who stated it was noisy have it too close to a wall, or a cupboard causing vibration.  It is very classy looking.  Guests love the appearance as do I.  I have mine on the floor next to a china cabinet with lots of air space around it.  I do not belie', '2025-09-21 13:09:02');
