INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (852, 35, 118, 5, 'I purchased this to replace a micro-hood and was thrilled to find it in bisque color since it matches everything else in my kitchen.  I decided against buying the bottom of the line hood since this one is enclosed and easier to keep clean.  We installed it vented outside and instructions were pretty clear.  The day after installation my husband realized the hood was ½-inch higher in front than in back (due to our cabinets and the wood blocks already there, nothing wrong with the hood) and it mea', '2025-11-15 13:09:02');
