INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (856, 34, 177, 2, 'I have had it two years. I don''t like the overheating front knobs and the door itself is hot. I''m surprised there isn''t a recall on this range. Also the gas knobs are easy to turn on accidently. The stainless streaks and the front glass leaks because there is a streak between the glass. I expected so much more from KitchenAid.  Report to consumers reports .', '2026-02-21 13:09:02');
