INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (859, 30, 16, 4, 'It makes ice , small bullets about 1&#34; long.It is slow as all of them.So if you are planing on party cook the ice days before , store it in zip-lock and keep it in the freezer and turn it on just while you party as an extra supply. The ice comes out wet and stick a little , I use meat tenderizer to separate ice while holding zip-lock with one hand in the air. You will not crush as much ice as if you put the bag flat on the surface and beat it. Wait 24 hours before operating it , the gas in th', '2025-11-06 13:09:02');
