INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (867, 22, 83, 5, 'We read the reviews before purchasing and glad we did not listen to a few negative ones. We have this outside in a pool cabana. We keep it reasonably full, not over stuffed. Everything has worked beautifully and it keeps things as cold as my inside fridge. Love the glass door so you can see in without having to open to see if it needs to be restocked. Also we did change the direction of the door opening. It took about 10 minutes and could not have been easier. Not sure where the negative reviews', '2025-07-02 13:09:02');
