INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (874, 23, 15, 5, '[[ASIN:B001AT2ALM Koldfront Ultra Compact Portable Ice Maker - White]]  This Ice Maker is perfect !!! It is quiet and the ice is  a perfect shape for a home unit !!! I was worried about when it would arrive at my home. Congrats to FedEx for an early deliver !!! It was an easy setup and it looks great on our counter top and did I mention it works quietly !!!!!! Thank you Amazon for an all around order!!!!!  I really appreciate all you do when I place an order !!!!!!', '2026-03-07 13:09:02');
