INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (876, 38, 87, 5, 'Pretty happy with the filter. Delivered fast and easy to install. It also has a good build quality.  Increased flow slightly so that was good. Excellent follow-up from the filter company. I filled the filter with cold water then installed it. You should then draw water through it for a few minutes to get rid of the filter taste then you are all set. I live in South Florida and our water is already good, so the filter mostly just removes any chlorine taste. Will definitely purchase again.', '2025-06-26 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (877, 22, 161, 5, 'Very useful.  Somehow lost the one I hd between stove and dishwasher. Worksgreat to keep stuff from falling in-between.  Delivered promptly.. all good.', '2025-10-01 13:09:02');
