INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (895, 38, 42, 1, 'Hate It!! This is my first experience with an Electrolux product and I was looking forward to owning one. I purchased the 4.3 Cu. Ft. Front Load Washer with IQ-Touch™ Controls featuring Perfect Steam in March and had it installed on the 23rd (2015). It is now April 25 and I hate this washing machine. I wish I had chosen a different brand. The technician has already been out once because I had a slow water leak coming down the front of the washer. The tech discovered there was a defect in the doo', '2026-03-12 13:09:02');
