INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (898, 39, 1, 4, 'This range hood was easy to install. The lights are very bright compared to the old single incandescent bulb of our old hood. Fan works well but is not the quietest. It looks O.K. but the rivets do show and that does kind of detract from the over all appearance but I can live with it. If your cupboards depth is more then 12&#34; the rivets should not show. All in all a decent hood.', '2025-12-19 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (899, 34, 76, 5, 'Love this machine! The tub is big - will wash 3 sets of sheets plus some clothes in one load. I''m 5''4&#34; and I can barely reach the bottom to get out the last few clothes. My fix is a child''s one-step stool, which enables me to lean over farther. This machine washes great, quietly and using much less water than our old one. The clothes come out after the spin cycle much drier, so there''s less time in the dryer.', '2025-05-23 13:09:02');
INSERT INTO Reviews (id, user_id, product_id, star_rating, content, created_at) VALUES (900, 22, 148, 5, 'Bought these for my old dishwasher - a must-have if you want to wash some non-stick pans in the dishwasher.  Bought more as soon as I moved into a new place - I don''t plan to be without these in any dishwasher in the future!', '2025-08-17 13:09:02');
